import sys
from typing import List
import collections

class Solution:
    def isNStraightHand(self, hand: List[int], groupSize: int) -> str:
        if len(hand) % groupSize != 0:
            return 'No'

        count = collections.Counter(hand)
        for card in sorted(count.keys()):
            if count[card] > 0:
                need = count[card]
                for i in range(card, card + groupSize):
                    if count[i] < need:
                        return 'No'
                    count[i] -= need
        return 'Yes'

if __name__ == '__main__':
