        n = int(sys.stdin.readline().strip())
        hand = list(map(int, sys.stdin.readline().strip().split()))
        groupSize = int(sys.stdin.readline().strip())
    except Exception as e:
        sys.exit(0)
    sol = Solution()
    ans = sol.isNStraightHand(hand, groupSize)
    print(ans)

