#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string isNStraightHand(vector<int>& hand, int groupSize) {
        if (hand.size() % groupSize != 0) {
            return "No";
        }

        unordered_map<int, int> count;
        for (int card : hand) {
            count[card]++;
        }

        for (int card : hand) {
            if (count[card] > 0) {
                int need = count[card];
                for (int i = card; i < card + groupSize; i++) {
                    if (count[i] < need) {
                        return "No";
                    }
                    count[i] -= need;
                }
            }
        }
        return "Yes";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> hand(n);
    for (int i = 0; i < n; i++) cin >> hand[i];
    int groupSize;
    cin >> groupSize;
    Solution sol;
    string ans = sol.isNStraightHand(hand, groupSize);
    cout << ans << endl;
    return 0;
}
